import React, { useRef, useEffect } from "react";
import { useGame } from "../context/GameContext";
import classicIcon from "../images/make/classic.svg";
import precisionIcon from "../images/make/precision.svg";
import speedIcon from "../images/make/speed.svg";

function HomePage() {
  const { state, dispatch } = useGame();
  const nameInputRef = useRef(null);

  // useRef + useEffect — autofocus the name input
  useEffect(() => {
    if (nameInputRef.current) {
      nameInputRef.current.focus();
    }
  }, []);

  const handleStart = () => {
    if (!state.playerName.trim()) {
      nameInputRef.current?.focus();
      return;
    }
    dispatch({ type: "SET_PAGE", payload: "game" });
  };

  const durations = [15, 30, 45, 60];
  const modes = [
    { id: "classic", title: "Classic", icon: classicIcon, desc: "Balanced targets" },
    { id: "precision", title: "Precision", icon: precisionIcon, desc: "Smaller targets, more points" },
    { id: "speed", title: "Speed", icon: speedIcon, desc: "Faster targets, reflex focus" },
  ];

  return (
    <div className="home-page">
      <div className="hero">
        <div className="hero-glow" />
        <h1 className="hero-title">
          AIM<span className="accent">TRAINER</span>
          <span className="hero-3d">3D</span>
        </h1>
        <p className="hero-sub">Train your aim in a 3D environment</p>
      </div>

      <div className="home-content">
        {/* Player Name */}
        <div className="card name-card">
          <h2>👤 Player Name</h2>
          <input
            ref={nameInputRef}
            type="text"
            placeholder="Enter your name..."
            className="name-input"
            value={state.playerName}
            onChange={(e) =>
              dispatch({ type: "SET_PLAYER_NAME", payload: e.target.value })
            }
            onKeyDown={(e) => e.key === "Enter" && handleStart()}
            maxLength={20}
          />
        </div>

        {/* Mode selection */}
        <div className="card">
          <h2>🎯 Mode</h2>
          <div className="mode-grid">
            {modes.map((m) => (
              <button
                key={m.id}
                className={`mode-btn ${state.gameSettings.mode === m.id ? "active" : ""}`}
                onClick={() => dispatch({ type: "SET_GAME_SETTINGS", payload: { mode: m.id } })}
                aria-pressed={state.gameSettings.mode === m.id}
              >
                <img src={m.icon} alt="" className="mode-icon" />
                <div className="mode-title">{m.title}</div>
                <div className="mode-desc">{m.desc}</div>
              </button>
            ))}
          </div>
        </div>

        {/* Duration */}
        <div className="card duration-card">
          <h2>⏱️ Duration</h2>
          <div className="duration-row">
            {durations.map((d) => (
              <button
                key={d}
                className={`dur-btn ${
                  state.gameSettings.duration === d ? "active" : ""
                }`}
                onClick={() =>
                  dispatch({
                    type: "SET_GAME_SETTINGS",
                    payload: { duration: d },
                  })
                }
              >
                {d}s
              </button>
            ))}
          </div>
        </div>

        {/* Actions */}
        <div className="home-actions">
          <button className="btn-primary btn-play" onClick={handleStart}>
            ▶ START TRAINING
          </button>
          <button
            className="btn-secondary"
            onClick={() =>
              dispatch({ type: "SET_PAGE", payload: "leaderboard" })
            }
          >
            🏆 Leaderboard
          </button>
        </div>

        {/* Conditional — show warning if no name */}
        {!state.playerName.trim() && (
          <p className="name-warning">⚠️ Enter your name to start</p>
        )}
      </div>
    </div>
  );
}

export default HomePage;
